import * as React from 'react';
import SearchOutlineOutlined from '@universe-design/icons-react/SearchOutlineOutlined';
import clsx from 'clsx';
import { useTransferContext } from '../hooks/TransferContext';
import type { InputProps } from '../../input';
import { Input } from '../../input';
import { useLocale } from '../../config-provider';
import { sxSearch } from '../sx';
import { forwardHTMLRef } from '../../util/forwardRef';

export type TransferSearchProps = Omit<InputProps, 'value' | 'onChange'>;

export const TransferSearch = forwardHTMLRef<TransferSearchProps, 'input'>((props, ref) => {
  const { className, onChange: onChangeProp, ...inputProps } = props;
  const { searchValue, setSearchValue, cssScope } = useTransferContext();
  const {
    global: { search },
  } = useLocale();

  const onChange: React.ChangeEventHandler<HTMLInputElement> = React.useCallback(
    e => {
      onChangeProp?.(e);
      setSearchValue(e.target.value);
    },
    [onChangeProp, setSearchValue],
  );

  return (
    <Input
      className={clsx(className, cssScope('__search'))}
      prefix={<SearchOutlineOutlined />}
      placeholder={search}
      {...inputProps}
      value={searchValue}
      onChange={onChange}
      sx={[sxSearch]}
      ref={ref}
    />
  );
});
